// Extract content from Claude's response
const claudeResponse = $input.first().json;
const content = claudeResponse.content[0].text;
const topic = $input.first().json.body?.topic || "Details Document";
const format = $input.first().json.body?.format || "pdf";
const currentDate = new Date().toLocaleDateString('en-US', { 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Format content for better readability
const formattedContent = content
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

return {
  json: {
    topic: topic,
    content: content,
    formattedContent: formattedContent,
    format: format,
    date: currentDate,
    filename: topic.replace(/[^a-z0-9]/gi, '_').toLowerCase()
  }
};

// Generate HTML for PDF
const item = $input.first().json;

const htmlContent = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${item.topic}</title>
    <style>
        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            line-height: 1.8;
            padding: 60px;
            max-width: 900px;
            margin: 0 auto;
            color: #333;
            background: #fff;
        }
        h1 {
            color: #1a1a1a;
            border-bottom: 4px solid #3498db;
            padding-bottom: 15px;
            margin-bottom: 10px;
            font-size: 32px;
        }
        .metadata {
            color: #7f8c8d;
            font-size: 14px;
            margin-bottom: 40px;
            font-style: italic;
        }
        .content {
            font-size: 16px;
            text-align: justify;
        }
        .content p {
            margin: 20px 0;
        }
        h2 {
            color: #2c3e50;
            margin-top: 30px;
            margin-bottom: 15px;
            font-size: 24px;
        }
        h3 {
            color: #34495e;
            margin-top: 25px;
            margin-bottom: 12px;
            font-size: 20px;
        }
        .footer {
            margin-top: 60px;
            padding-top: 20px;
            border-top: 2px solid #ecf0f1;
            text-align: center;
            color: #95a5a6;
            font-size: 12px;
        }
    </style>
</head>
<body>
    <h1>${item.topic}</h1>
    <div class="metadata">Generated on ${item.date}</div>
    <div class="content">
        <p>${item.formattedContent}</p>
    </div>
    <div class="footer">
        Document generated automatically | ${item.date}
    </div>
</body>
</html>
`;

return {
  json: {
    ...item,
    html: htmlContent
  }
};

// Generate DOCX-compatible HTML
const item = $input.first().json;

const docxHtml = `
<html xmlns:o="urn:schemas-microsoft-com:office:office"
      xmlns:w="urn:schemas-microsoft-com:office:word"
      xmlns="http://www.w3.org/TR/REC-html40">
<head>
    <meta charset="utf-8">
    <title>${item.topic}</title>
    <style>
        body {
            font-family: Calibri, sans-serif;
            font-size: 11pt;
            line-height: 1.6;
        }
        h1 {
            font-size: 24pt;
            font-weight: bold;
            color: #1f4e78;
            margin-bottom: 10pt;
            border-bottom: 3pt solid #4472c4;
            padding-bottom: 5pt;
        }
        .metadata {
            font-size: 10pt;
            color: #7f7f7f;
            font-style: italic;
            margin-bottom: 20pt;
        }
        p {
            margin: 10pt 0;
            text-align: justify;
        }
        h2 {
            font-size: 16pt;
            font-weight: bold;
            color: #2e5c8a;
            margin-top: 15pt;
            margin-bottom: 8pt;
        }
    </style>
</head>
<body>
    <h1>${item.topic}</h1>
    <p class="metadata">Generated on ${item.date}</p>
    <div>
        <p>${item.formattedContent}</p>
    </div>
</body>
</html>
`;

return {
  json: {
    ...item,
    docxHtml: docxHtml
  }
};
